// Collect mapped events from every feed, then (a) keep only the near-term
// window — raw ICS feeds dump full history (years of events) — and (b)
// guarantee a title, since ICS events without SUMMARY would 422 the whole
// batch. Window ~36h matches the original OAuth design.
const now = Date.now();
const FROM = now - 60 * 60 * 1000;
const TO = now + 36 * 60 * 60 * 1000;
const events = $input.all()
  .map((i) => i.json)
  .filter((e) => { const t = Date.parse(e.start_at); return !Number.isNaN(t) && t >= FROM && t <= TO; })
  .map((e) => ({ ...e, title: (e.title && String(e.title).trim()) || '(busy)' }));
return [{ json: { events } }];
